* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  font-family: "Sharp Grotesk";
  background: #e7e4e5;
  overflow: hidden;
}

.loader {
  position: fixed;
  width: 100vw;
  height: 100vh;
  background: #000;
  clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%);
  pointer-events: none;
}

.loader-imgs {
  width: 150%;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  display: flex;
  gap: 50px;
  clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%);
}

.img {
  position: relative;
  flex: 1;
  clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%);
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

nav {
  width: 100%;
  padding: 30px;
  display: flex;
  align-items: center;
  font-family: "Neue Montreal";
}

.nav-item {
  position: relative;
  flex: 1;
}

.nav-item:nth-child(2) {
  text-align: center;
  font-family: "PP Editorial Old";
  font-size: 24px;
  font-weight: 500;
}

.nav-item:nth-child(3) {
  text-align: right;
}

#logo a {
  text-transform: none;
}

a {
  text-decoration: none;
  text-transform: uppercase;
  color: #000;
}

.hero {
  width: 100%;
  position: absolute;
  top: 45%;
  transform: translateY(-50%);
  text-transform: uppercase;
  font-family: "PP Migra";
}

.h1 {
  width: 100%;
  text-align: center;
  font-size: 4vw;
  clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%);
}

h1 {
  position: relative;
  font-weight: 400;
  line-height: 85%;
}

h1 span {
  font-family: "Sharp Grotesk";
  font-weight: 700;
}

footer {
  width: 100%;
  position: absolute;
  bottom: 30px;
  right: 30px;
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%);
}

.item {
  position: relative;
  width: 100px;
  height: 100px;
}
